// 三重匹配：原文 | 全拼 | 首字母
function fuzzyMatch(name, term) {
  if (!term) return true;
  const t = term.toLowerCase().replace(/\s/g, '');
  if (name.toLowerCase().includes(t)) return true;
  if (toPinyin(name).includes(t)) return true;
  if (toPinyinInitials(name).includes(t)) return true;
  return false;
}
